using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, quantities, shapes, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        var instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers and holds 3 patents in neural network architectures.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Miller", Title = "Associate Professor", Bio = "Dr. Miller's research focuses on distributed systems and cloud computing. He previously worked at a major tech company for 10 years.", Email = "j.miller@university.edu" },
            new() { Id = 3, Name = "Dr. Emily Rodriguez", Title = "Professor", Bio = "Dr. Rodriguez is an expert in abstract algebra and number theory. She received the Distinguished Teaching Award in 2023.", Email = "e.rodriguez@university.edu" },
            new() { Id = 4, Name = "Dr. Michael Thompson", Title = "Assistant Professor", Bio = "Dr. Thompson researches quantum mechanics and particle physics. He completed his postdoc at CERN.", Email = "m.thompson@university.edu" },
            new() { Id = 5, Name = "Dr. Lisa Park", Title = "Professor", Bio = "Dr. Park is a published novelist and literary critic specializing in contemporary American fiction.", Email = "l.park@university.edu" },
            new() { Id = 6, Name = "Dr. Robert Williams", Title = "Associate Professor", Bio = "Dr. Williams is a historian focusing on the Civil Rights era and modern American political history.", Email = "r.williams@university.edu" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 301", Title = "Artificial Intelligence", Description = "Explore the principles and techniques of AI including search algorithms, knowledge representation, machine learning, and natural language processing.", Credits = 4, Schedule = "Tue/Thu 10:00–11:50 AM", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[0], IsFeatured = true },
            new() { Id = 3, Code = "CS 250", Title = "Distributed Systems", Description = "Study the design and implementation of distributed computing systems, including consensus protocols, replication, and fault tolerance.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[1], IsFeatured = false },
            new() { Id = 4, Code = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2], IsFeatured = true },
            new() { Id = 5, Code = "MATH 301", Title = "Abstract Algebra", Description = "Groups, rings, fields, and homomorphisms. A rigorous introduction to algebraic structures.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2], IsFeatured = false },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM + Lab Thu 2:00–4:50 PM", DepartmentId = 3, DepartmentName = "Physics", Instructor = instructors[3], IsFeatured = false },
            new() { Id = 7, Code = "PHYS 310", Title = "Quantum Mechanics", Description = "Wave functions, Schrödinger equation, quantum operators, and applications to atomic and molecular systems.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = 3, DepartmentName = "Physics", Instructor = instructors[3], IsFeatured = true },
            new() { Id = 8, Code = "ENG 110", Title = "Creative Writing", Description = "Workshop-based course covering fiction, poetry, and creative nonfiction. Students produce a portfolio of original work.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4], IsFeatured = false },
            new() { Id = 9, Code = "ENG 250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present day.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4], IsFeatured = false },
            new() { Id = 10, Code = "HIST 200", Title = "Modern American History", Description = "The United States from Reconstruction to the present, focusing on social movements, politics, and cultural change.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", DepartmentId = 5, DepartmentName = "History", Instructor = instructors[5], IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

