arguments.file_text:
@page "/"

@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="hero">
    <h1>University Course Catalog</h1>
    <p>Explore our departments and courses for the upcoming semester.</p>
    <a href="/courses" class="btn-primary">Browse All Courses</a>
</div>

<section class="featured-section">
    <h2>Featured Courses</h2>
    <div class="course-grid">
        @foreach (var course in featuredCourses)
        {
            <div class="course-card">
                <span class="course-code">@course.Code</span>
                <h3>@course.Title</h3>
                <p>@course.Credits credits &middot; @course.DepartmentName</p>
                <p class="course-instructor">@course.Instructor.Name</p>
                <a href="/courses/@course.Id">View Details</a>
            </div>
        }
    </div>
</section>

<section class="departments-section">
    <h2>Departments</h2>
    <div class="department-grid">
        @foreach (var dept in departments)
        {
            <div class="department-card">
                <h3>@dept.Name</h3>
                <p>@dept.Description</p>
                <a href="/courses?department=@dept.Id">View Courses</a>
            </div>
        }
    </div>
</section>

@code {
    private List<UniversityCourseCatalog.Models.Course> featuredCourses = new();
    private List<UniversityCourseCatalog.Models.Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@rendermode InteractiveServer

@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="search-filters">
    <input type="text" @bind="searchTerm" @bind:event="oninput" placeholder="Search courses, instructors..." class="search-input" />
    <select @bind="selectedDepartment" class="filter-select">
        <option value="0">All Departments</option>
        @foreach (var dept in departments)
