@page "/enroll"

@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<nav class="breadcrumb">
    <a href="/">Home</a> &rsaquo;
    <a href="/courses">Courses</a> &rsaquo;
    <span>Enroll</span>
</nav>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>Request Submitted</h2>
        <p>Your enrollment request has been submitted successfully. You will receive a confirmation via your university email.</p>
        <a href="/courses" class="btn-primary">Back to Courses</a>
    </div>
}
else
{
    <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
        <AntiforgeryToken />

        <div class="form-group">
            <label for="studentName">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" @bind="Model.StudentName" required />
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" @bind="Model.StudentId" required placeholder="e.g., STU-12345" />
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <select id="courseId" name="Model.CourseId" @bind="Model.CourseId" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.Code - @course.Title</option>
                }
            </select>
        </div>

        <div class="form-actions">
            <button type="submit" class="btn-primary">Submit Request</button>
            <a href="/courses" class="btn-secondary">Cancel</a>
        </div>
    </form>
}

@code {
    [SupplyParameterFromForm]
    private UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    private int? CourseId { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        if (!string.IsNullOrWhiteSpace(Model.StudentName) &&
            !string.IsNullOrWhiteSpace(Model.StudentId) &&
            Model.CourseId > 0)
        {
            CatalogService.SubmitEnrollment(Model);
            submitted = true;
        }
    }
}

