arguments.new_str:
html, body {
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
}

a, .btn-link {
    color: #006bb7;
}

.btn-primary,
a.btn-primary {
    display: inline-block;
    padding: 0.6rem 1.2rem;
    color: #fff;
    background-color: #1b6ec2;
    border: 1px solid #1861ac;
    border-radius: 4px;
    text-decoration: none;
    font-size: 0.95rem;
    cursor: pointer;
}

.btn-primary:hover {
    background-color: #155a9c;
}

.btn-secondary,
a.btn-secondary {
    display: inline-block;
    padding: 0.6rem 1.2rem;
    color: #333;
    background-color: #e9ecef;
    border: 1px solid #ced4da;
    border-radius: 4px;
    text-decoration: none;
    font-size: 0.95rem;
    cursor: pointer;
}

.btn-secondary:hover {
    background-color: #dde2e6;
}

.btn:focus, .btn:active:focus, .btn-link.nav-link:focus, .form-control:focus, .form-check-input:focus {
  box-shadow: 0 0 0 0.1rem white, 0 0 0 0.25rem #258cfb;
}

.content {
    padding-top: 1.1rem;
}

h1:focus {
    outline: none;
}

/* Hero */
.hero {
    background: linear-gradient(135deg, #1b6ec2, #2d8cf0);
    color: white;
    padding: 3rem 2rem;
    border-radius: 8px;
    margin-bottom: 2rem;
    text-align: center;
}

.hero h1 {
    margin: 0 0 0.5rem;
    font-size: 2rem;
}

.hero p {
    margin: 0 0 1.5rem;
    font-size: 1.1rem;
    opacity: 0.9;
}

.hero .btn-primary {
    background-color: #fff;
    color: #1b6ec2;
    border-color: #fff;
    font-weight: 600;
}

/* Sections */
.featured-section,
.departments-section {
    margin-bottom: 2.5rem;
}

.featured-section h2,
.departments-section h2 {
    margin-bottom: 1rem;
    border-bottom: 2px solid #e9ecef;
    padding-bottom: 0.5rem;
}

/* Course Grid */
.course-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 1.2rem;
}

.course-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.2rem;
    transition: box-shadow 0.2s;
}

.course-card:hover {
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
}

.course-card h3 {
    margin: 0.5rem 0 0.3rem;
    font-size: 1.1rem;
}

.course-card .course-code {
    font-size: 0.85rem;
    color: #1b6ec2;
    font-weight: 600;
}

.course-card .course-instructor {
    color: #666;
    font-style: italic;
}

/* Department Grid */
.department-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
    gap: 1rem;
}

.department-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.2rem;
}

.department-card h3 {
    margin: 0 0 0.5rem;
    color: #1b6ec2;
}

/* Search & Filters */
.search-filters {
    display: flex;
    gap: 1rem;
    margin-bottom: 1.5rem;
    flex-wrap: wrap;
}

.search-input {
    flex: 1;
    min-width: 200px;
    padding: 0.6rem 1rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 1rem;
}

.filter-select {
    padding: 0.6rem 1rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 1rem;
    min-width: 180px;
}

.results-count {
    color: #666;
    margin-bottom: 1rem;
}

/* Course List */
.course-list-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 1.2rem;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    margin-bottom: 0.75rem;
    flex-wrap: wrap;
    gap: 1rem;
}

.course-list-info h3 {
    margin: 0.2rem 0;
    font-size: 1.05rem;
}

.course-list-info .course-code {
    font-size: 0.85rem;
    color: #1b6ec2;
    font-weight: 600;
}

.course-list-info .course-instructor {
    color: #666;
    font-style: italic;
    margin: 0;
}

.course-list-actions {
    display: flex;
    gap: 0.5rem;
}

.no-results {
    text-align: center;
    color: #666;
    padding: 2rem;
}

/* Course Detail */
.breadcrumb {
    margin-bottom: 1.5rem;
    color: #666;
}

.breadcrumb a {
    text-decoration: none;
}

.course-detail-header {
    margin-bottom: 2rem;
}

.course-detail-header .course-code {
    color: #1b6ec2;
    font-weight: 600;
}

.course-detail-header h1 {
    margin: 0.3rem 0;
}

.department-label {
    color: #666;
    font-size: 1.05rem;
}

.course-detail-body {
    display: grid;
    gap: 2rem;
}

.course-description p {
    line-height: 1.6;
}

.course-meta {
    display: flex;
    gap: 2rem;
    flex-wrap: wrap;
    background: #f8f9fa;
    padding: 1.2rem;
    border-radius: 8px;
}

.meta-item {
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
}

.meta-item strong {
    color: #333;
    font-size: 0.85rem;
    text-transform: uppercase;
}

.instructor-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.5rem;
}

.instructor-card h3 {
    margin: 0 0 0.2rem;
}

.instructor-title {
    color: #1b6ec2;
    margin: 0 0 0.8rem;
}

.instructor-email {
    color: #666;
    font-size: 0.9rem;
    margin-top: 0.8rem;
}

.course-actions {
    display: flex;
    gap: 1rem;
    margin-top: 1rem;
}

/* Forms */
form {
    max-width: 500px;
}

.form-group {
    margin-bottom: 1.2rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 600;
    color: #333;
}

.form-group input,
.form-group select {
    width: 100%;
    padding: 0.6rem 0.8rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 1rem;
}

.form-actions {
    display: flex;
    gap: 1rem;
    margin-top: 1.5rem;
}

.success-message {
    background: #d4edda;
    border: 1px solid #c3e6cb;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
}

.success-message h2 {
    color: #155724;
    margin: 0 0 0.5rem;
}

/* Error UI */
.valid.modified:not([type=checkbox]) {
    outline: 1px solid #26b050;
}

.invalid {
    outline: 1px solid #e50000;
}

.validation-message {
    color: #e50000;
}

.blazor-error-boundary {
    background: url(data:image/svg+xml;base64,) no-repeat 1rem/1.8rem, #b32121;
    padding: 1rem 1rem 1rem 3.7rem;
    color: white;
}

    .blazor-error-boundary::after {
        content: "An error has occurred."
    }

.darker-border-checkbox.form-check-input {
    border-color: #929292;
}

.form-floating > .form-control-plaintext::placeholder, .form-floating > .form-control::placeholder {
    color: var(--bs-secondary-color);
    text-align: end;
}

.form-floating > .form-control-plaintext:focus::placeholder, .form-floating > .form-control:focus::placeholder {
    text-align: start;
}

