    gap: 2rem;
}

.course-description p {
    line-height: 1.6;
}

.course-meta {
    display: flex;
    gap: 2rem;
    flex-wrap: wrap;
    background: #f8f9fa;
    padding: 1.2rem;
    border-radius: 8px;
}

.meta-item {
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
}

.meta-item strong {
    color: #333;
    font-size: 0.85rem;
    text-transform: uppercase;
}

.instructor-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.5rem;
}

.instructor-card h3 {
    margin: 0 0 0.2rem;
}

.instructor-title {
    color: #1b6ec2;
    margin: 0 0 0.8rem;
}

.instructor-email {
    color: #666;
    font-size: 0.9rem;
    margin-top: 0.8rem;
}

.course-actions {
    display: flex;
    gap: 1rem;
    margin-top: 1rem;
}

/* Forms */
form {
    max-width: 500px;
}

.form-group {
    margin-bottom: 1.2rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 600;
    color: #333;
}

.form-group input,
.form-group select {
    width: 100%;
    padding: 0.6rem 0.8rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 1rem;
}

.form-actions {
    display: flex;
    gap: 1rem;
    margin-top: 1.5rem;
}

.success-message {
    background: #d4edda;
    border: 1px solid #c3e6cb;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
}

.success-message h2 {
    color: #155724;
    margin: 0 0 0.5rem;
}

/* Error UI */
.valid.modified:not([type=checkbox]) {
    outline: 1px solid #26b050;
}

.invalid {
    outline: 1px solid #e50000;
}

.validation-message {
    color: #e50000;
}

.blazor-error-boundary {
    background: url(data:image/svg+xml;base64,) no-repeat 1rem/1.8rem, #b32121;
    padding: 1rem 1rem 1rem 3.7rem;
    color: white;
}

    .blazor-error-boundary::after {
        content: "An error has occurred."
    }

.darker-border-checkbox.form-check-input {
    border-color: #929292;
}

.form-floating > .form-control-plaintext::placeholder, .form-floating > .form-control::placeholder {
    color: var(--bs-secondary-color);
    text-align: end;
}

.form-floating > .form-control-plaintext:focus::placeholder, .form-floating > .form-control:focus::placeholder {
    text-align: start;
}

